styles:
:root {
  --tc-bg: #ffffff;
  --tc-text: var(--ink, #0c2b4f);
  --tc-muted: var(--muted, #8493a6);
  --tc-line: var(--line, #e7ecf1);
  --tc-accent-soft: var(--green-50, #e9f9f1);
  --tc-radius: var(--r-lg, 24px);
  --tc-shadow: var(--shadow, 0 18px 40px -18px rgba(12, 43, 79, .22));
  --tc-font: var(--font, 'Outfit', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif);
}

:root .cb-testimonial-card {
  position: relative;
  background: linear-gradient(180deg, #ffffff 0%, var(--bg-soft2, #f6f9fb) 140%);
  border: 1px solid var(--tc-line);
  border-radius: var(--tc-radius);
  box-shadow: var(--tc-shadow);
  padding: 32px;
  overflow: hidden;
  font-family: var(--tc-font);
}

:root .cb-testimonial-card::before {
  content: "";
  position: absolute;
  inset: 0 0 auto auto;
  width: 140px;
  height: 140px;
  background: radial-gradient(circle at center, var(--tc-accent-soft) 0%, rgba(233, 249, 241, 0) 72%);
  pointer-events: none;
}

:root .testimonial__top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 14px;
}

:root .testimonial__quote-mark {
  display: grid;
  place-items: center;
  width: 52px;
  height: 52px;
  border-radius: 16px;
  background: var(--tc-accent-soft);
  color: var(--green-700, #0c8b4b);
  font-size: 34px;
  font-weight: 700;
  line-height: 1;
}

:root .testimonial__stars {
  display: flex;
  gap: 4px;
  margin-bottom: 0;
  font-size: 18px;
  letter-spacing: .02em;
}

:root .testimonial__stars span {
  color: var(--green, #15c46c);
}

:root .testimonial__quote {
  color: var(--tc-text);
  font-size: 17px;
  line-height: 1.7;
  text-wrap: pretty;
}

:root .testimonial__author {
  display: flex;
  align-items: center;
  gap: 14px;
  margin-top: 24px;
  padding-top: 20px;
  border-top: 1px solid var(--line-2, #eef2f6);
}

:root .testimonial__avatar {
  display: grid;
  place-items: center;
  width: 50px;
  height: 50px;
  flex-shrink: 0;
  border-radius: 50%;
  color: #ffffff;
  font-size: 16px;
  font-weight: 700;
  box-shadow: 0 10px 22px -10px rgba(12, 43, 79, .35);
}

:root .testimonial__meta {
  min-width: 0;
}

:root .testimonial__name {
  color: var(--tc-text);
  font-size: 15.5px;
  font-weight: 700;
  line-height: 1.25;
}

:root .testimonial__role {
  margin-top: 3px;
  color: var(--tc-muted);
  font-size: 13.5px;
  line-height: 1.35;
}

@media (max-width: 767px) {
  :root .cb-testimonial-card {
    padding: 24px;
    border-radius: 20px;
  }

  :root .testimonial__top {
    align-items: flex-start;
  }

  :root .testimonial__quote {
    font-size: 16px;
    line-height: 1.65;
  }

  :root .testimonial__quote-mark {
    width: 46px;
    height: 46px;
    font-size: 30px;
  }
}
